import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { CartContext } from '../context/CartContext';

const ProductCard = ({ product }) => {
  const { addToCart } = useContext(CartContext);
  const discountedPrice = product.price * (1 - (product.discount || 0) / 100);

  return (
    <div className="card h-100">
      <Link to={`/products/${product._id}`}>
        <img src={product.image} className="card-img-top" alt={product.name} style={{ height: '200px', objectFit: 'cover' }} />
      </Link>
      <div className="card-body d-flex flex-column">
        <h5 className="card-title" style={{ fontSize: '1rem' }}>{product.name}</h5>
        <p className="card-text mb-1">
          Rating: {product.rating?.toFixed(1) || 'N/A'}
        </p>
        <p className="card-text mb-1">
          {product.discount > 0 ? (
            <>
              <span className="text-muted text-decoration-line-through">${product.price.toFixed(2)}</span>{' '}
              <span className="fw-bold text-success">${discountedPrice.toFixed(2)}</span>{' '}
              <span className="badge bg-danger">-{product.discount}%</span>
            </>
          ) : (
            <span className="fw-bold">${product.price.toFixed(2)}</span>
          )}
        </p>
        <p className="card-text mb-2">
          Stock: {product.stock > 0 ? product.stock : <span className="text-danger">Out of stock</span>}
        </p>
        <button
          className="btn btn-primary mt-auto"
          onClick={() => addToCart(product)}
          disabled={product.stock === 0}
        >
          Add to Cart
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
